import { mkdir, readdir, rm, writeFile } from 'node:fs/promises';
import { resolve } from 'node:path';
import sharp from 'sharp';

const THUMBNAIL_FILE_PATTERN = /^loadscreen_(.+)\.jpg$/i;

function buildManifestSource(entries) {
  const lines = [
    '// Auto-generated by scripts/build-thumbnails.mjs. Do not edit manually.',
    'export const T6_THUMBNAIL_FILES = {'
  ];

  const sorted = [...entries].sort((left, right) => left.slug.localeCompare(right.slug));
  for (let i = 0; i < sorted.length; i++) {
    const entry = sorted[i];
    lines.push('  ' + JSON.stringify(entry.slug) + ': ' + JSON.stringify(entry.fileName) + ',');
  }

  lines.push('};');
  lines.push('');
  return lines.join('\n');
}

export async function buildThumbnails(workspaceRoot) {
  const srcDir = resolve(workspaceRoot, 'src/t6_map_thumbnails');
  const distDir = resolve(workspaceRoot, 'dist/t6_map_thumbnails_16x9');
  const generatedDir = resolve(workspaceRoot, 'src/generated');
  const manifestPath = resolve(generatedDir, 't6-thumbnail-manifest.js');

  let dirEntries = [];
  try {
    dirEntries = await readdir(srcDir, { withFileTypes: true });
  } catch (error) {
    if (!error || error.code !== 'ENOENT') {
      throw error;
    }
  }

  const thumbnails = [];
  for (let i = 0; i < dirEntries.length; i++) {
    const entry = dirEntries[i];
    if (!entry.isFile()) continue;

    const match = THUMBNAIL_FILE_PATTERN.exec(entry.name);
    if (!match) continue;

    thumbnails.push({
      slug: String(match[1]).toLowerCase(),
      fileName: entry.name,
      sourcePath: resolve(srcDir, entry.name),
      outputPath: resolve(distDir, entry.name)
    });
  }

  await rm(distDir, { recursive: true, force: true });
  await mkdir(distDir, { recursive: true });
  await mkdir(generatedDir, { recursive: true });

  for (let i = 0; i < thumbnails.length; i++) {
    const thumbnail = thumbnails[i];
    await sharp(thumbnail.sourcePath)
      .resize(1920, 1080, { fit: 'fill' })
      .jpeg({ quality: 90 })
      .toFile(thumbnail.outputPath);
  }

  await writeFile(manifestPath, buildManifestSource(thumbnails), 'utf8');

  return {
    count: thumbnails.length,
    outputDir: distDir,
    manifestPath: manifestPath
  };
}

if (import.meta.url === `file://${process.argv[1]}`) {
  const workspaceRoot = resolve(import.meta.dirname, '..');
  const result = await buildThumbnails(workspaceRoot);
  console.log(`Built ${result.count} stretched thumbnails into ${result.outputDir}`);
}
